import React, { useState, useEffect } from 'react';
import { Edit, Trash2, Eye, X, Plus, Users, Star, DollarSign, BookOpen, TrendingUp, Upload, Link, Image, BarChart3, Calendar, Award, Target } from 'lucide-react';
import StatsCard from './components/StatsCard.jsx';
import LoadingSpinner from './components/LoadingSpinner.jsx';
import { useToast } from './components/Toast';
import { removeDuplicateCourses, validateCourse } from './utils/courseUtils';

const InstructorDashboard = ({ courses, onAddCourse, onUpdateCourse, onDeleteCourse }) => {
  const { showToast } = useToast();
  const [showEditModal, setShowEditModal] = useState(false);
  const [showPreviewModal, setShowPreviewModal] = useState(false);
  const [showAddModal, setShowAddModal] = useState(false);
  const [selectedCourse, setSelectedCourse] = useState(null);
  const [localCourses, setLocalCourses] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterLevel, setFilterLevel] = useState('all');
  const [isLoading, setIsLoading] = useState(false);
  const [courseForm, setCourseForm] = useState({
    title: '',
    desc: '',
    price: '',
    level: 'Beginner',
    cat: 'development',
    time: '',
    instructor: 'Current User',
    videoType: 'upload',
    videoFile: null,
    youtubeLink: '',
    dropboxLink: '',
    videoLink: '',
    thumbnailUrl: '',
    videoLinks: [],
    newVideoUrl: ''
  });

  // Load courses from localStorage on component mount
  useEffect(() => {
    const savedCourses = JSON.parse(localStorage.getItem('instructorCourses') || '[]');
    const uniqueCourses = removeDuplicateCourses(savedCourses);
    if (uniqueCourses.length !== savedCourses.length) {
      localStorage.setItem('instructorCourses', JSON.stringify(uniqueCourses));
    }
    setLocalCourses(uniqueCourses);
  }, []);

  const filteredCourses = localCourses.filter(course => {
    const matchesSearch = course.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         course.desc.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesLevel = filterLevel === 'all' || course.level === filterLevel;
    return matchesSearch && matchesLevel;
  });

  const allCourses = localCourses;

  const stats = {
    totalCourses: allCourses.length,
    totalStudents: allCourses.reduce((sum, course) => sum + (course.enrolled || 0), 0),
    totalRevenue: allCourses.reduce((sum, course) => sum + ((course.price || 0) * (course.enrolled || 0)), 0),
    avgRating: allCourses.length > 0 ? (allCourses.reduce((sum, course) => sum + parseFloat(course.rating || 0), 0) / allCourses.length).toFixed(1) : '0.0'
  };

  const editCourse = (course) => {
    setSelectedCourse(course);
    setCourseForm({
      title: course.title,
      desc: course.desc,
      price: course.price.toString(),
      level: course.level,
      cat: course.cat,
      time: course.time,
      instructor: course.instructor,
      videoType: course.videoType || 'upload',
      videoFile: course.videoFile || null,
      youtubeLink: course.youtubeLink || '',
      dropboxLink: course.dropboxLink || '',
      videoLink: course.videoLink || '',
      thumbnailUrl: course.thumbnailUrl || '',
      videoLinks: course.videoLinks || [],
      newVideoUrl: ''
    });
    setShowEditModal(true);
  };

  const previewCourse = (course) => {
    setSelectedCourse(course);
    setShowPreviewModal(true);
  };

  const deleteCourse = async (courseId, courseTitle) => {
    if (window.confirm(`Delete "${courseTitle}"?`)) {
      try {
        // Delete from API/main courses
        if (onDeleteCourse) {
          await onDeleteCourse(courseId);
        }

        // Delete from localStorage
        const savedCourses = JSON.parse(localStorage.getItem('instructorCourses') || '[]');
        const updatedCourses = savedCourses.filter(course => course.id !== courseId);
        localStorage.setItem('instructorCourses', JSON.stringify(updatedCourses));
        setLocalCourses(updatedCourses);
      } catch (error) {
        console.error('Failed to delete course:', error);
        alert('Failed to delete course. Please try again.');
      }
    }
  };

  const closeModal = (modalType) => {
    if (modalType === 'edit') {
      setShowEditModal(false);
    } else if (modalType === 'preview') {
      setShowPreviewModal(false);
    } else {
      setShowAddModal(false);
    }
    setSelectedCourse(null);
    setCourseForm({ 
      title: '', desc: '', price: '', level: 'Beginner', cat: 'development', time: '', 
      instructor: 'Current User', videoType: 'upload', videoFile: null, youtubeLink: '', 
      dropboxLink: '', videoLink: '', thumbnailUrl: '', videoLinks: [], newVideoUrl: '' 
    });
  };

  const handleFileUpload = (e) => {
    const file = e.target.files[0];
    if (file && file.type.startsWith('video/')) {
      setCourseForm({...courseForm, videoFile: file});
    }
  };

  const addVideoLink = () => {
    if (courseForm.newVideoUrl && courseForm.newVideoUrl.trim()) {
      setCourseForm({
        ...courseForm,
        videoLinks: [...(courseForm.videoLinks || []), courseForm.newVideoUrl.trim()],
        newVideoUrl: ''
      });
    }
  };

  const removeVideoLink = (index) => {
    setCourseForm({
      ...courseForm,
      videoLinks: courseForm.videoLinks.filter((_, i) => i !== index)
    });
  };

  const handleEditSubmit = async (e) => {
    e.preventDefault();
    if (courseForm.title && courseForm.desc && courseForm.price && selectedCourse) {
      setIsLoading(true);
      try {
        const updatedCourse = {
          title: courseForm.title,
          desc: courseForm.desc,
          price: parseInt(courseForm.price),
          level: courseForm.level,
          cat: courseForm.cat,
          time: courseForm.time,
          instructor: courseForm.instructor,
          videoType: courseForm.videoType,
          videoFile: courseForm.videoFile,
          youtubeLink: courseForm.youtubeLink,
          dropboxLink: courseForm.dropboxLink,
          videoLink: courseForm.videoLink,
          thumbnailUrl: courseForm.thumbnailUrl,
          videoLinks: courseForm.videoLinks,
          img: courseForm.thumbnailUrl || selectedCourse.img
        };

        if (onUpdateCourse) {
          await onUpdateCourse(selectedCourse.id, updatedCourse);
        }

        // Update local courses as well
        const savedCourses = JSON.parse(localStorage.getItem('instructorCourses') || '[]');
        const updatedCourses = savedCourses.map(course => 
          course.id === selectedCourse.id ? { ...selectedCourse, ...updatedCourse } : course
        );
        localStorage.setItem('instructorCourses', JSON.stringify(updatedCourses));
        setLocalCourses(updatedCourses);

        closeModal('edit');
      } catch (error) {
        console.error('Failed to update course:', error);
        alert('Failed to update course. Please try again.');
      } finally {
        setIsLoading(false);
      }
    }
  };

  const handleAddSubmit = async (e) => {
    e.preventDefault();
    if (courseForm.title && courseForm.desc && courseForm.price) {
      setIsLoading(true);
      try {
        const newCourse = {
          title: courseForm.title,
          desc: courseForm.desc,
          price: parseInt(courseForm.price),
          level: courseForm.level,
          cat: courseForm.cat,
          time: courseForm.time,
          instructor: courseForm.instructor,
          img: courseForm.thumbnailUrl || 'https://images.unsplash.com/photo-1516321318423-f06f85e504b3?w=400&h=200&fit=crop',
          videoType: courseForm.videoType,
          videoFile: courseForm.videoFile,
          youtubeLink: courseForm.youtubeLink,
          dropboxLink: courseForm.dropboxLink,
          videoLink: courseForm.videoLink,
          thumbnailUrl: courseForm.thumbnailUrl,
          videoLinks: courseForm.videoLinks
        };

        let createdCourse;
        if (onAddCourse) {
          createdCourse = await onAddCourse(newCourse);
        }

        // Also save to localStorage for instructor dashboard
        const savedCourses = JSON.parse(localStorage.getItem('instructorCourses') || '[]');
        const courseToSave = createdCourse || { ...newCourse, id: Date.now(), enrolled: 0, rating: '5.0' };
        const updatedCourses = [...savedCourses, courseToSave];
        const uniqueCourses = removeDuplicateCourses(updatedCourses);
        localStorage.setItem('instructorCourses', JSON.stringify(uniqueCourses));
        setLocalCourses(uniqueCourses);
        showToast('Course added successfully!', 'success');

        closeModal('add');
      } catch (error) {
        console.error('Failed to add course:', error);
        alert('Failed to add course. Please try again.');
      } finally {
        setIsLoading(false);
      }
    }
  };

  return (
    <div style={{minHeight: '100vh', background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)', padding: '2rem'}}>
      {/* Header */}
      <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem'}}>
        <div>
          <h1 style={{fontSize: '3rem', fontWeight: 'bold', color: 'white', textShadow: '2px 2px 4px rgba(0,0,0,0.3)', marginBottom: '0.5rem'}}>
            🎓 Instructor Dashboard
          </h1>
          <p style={{color: 'rgba(255,255,255,0.9)', fontSize: '1.1rem', fontWeight: '500'}}>
            Manage your courses and track performance
          </p>
        </div>
        <button 
          onClick={() => setShowAddModal(true)}
          style={{
            background: 'linear-gradient(45deg, #ff6b6b, #ee5a24)', 
            color: 'white', 
            padding: '1rem 2rem', 
            borderRadius: '50px', 
            border: 'none', 
            cursor: 'pointer', 
            display: 'flex', 
            alignItems: 'center', 
            gap: '0.5rem', 
            fontSize: '1.1rem', 
            fontWeight: '600',
            boxShadow: '0 8px 25px rgba(255,107,107,0.3)',
            transform: 'translateY(0)',
            transition: 'all 0.3s ease'
          }}
          onMouseOver={(e) => {
            e.target.style.transform = 'translateY(-2px)';
            e.target.style.boxShadow = '0 12px 35px rgba(255,107,107,0.4)';
          }}
          onMouseOut={(e) => {
            e.target.style.transform = 'translateY(0)';
            e.target.style.boxShadow = '0 8px 25px rgba(255,107,107,0.3)';
          }}
        >
          <Plus style={{width: '1.5rem', height: '1.5rem'}} />
          Add Course
        </button>
      </div>

      {/* Enhanced Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        <StatsCard
          title="Total Courses"
          value={stats.totalCourses}
          icon={BookOpen}
          color="blue"
          trend={12}
          description="Active courses in your portfolio"
        />
        <StatsCard
          title="Total Students"
          value={stats.totalStudents}
          icon={Users}
          color="green"
          trend={8}
          description="Enrolled across all courses"
        />
        <StatsCard
          title="Total Revenue"
          value={stats.totalRevenue}
          icon={DollarSign}
          color="purple"
          prefix="₹"
          trend={15}
          description="Lifetime earnings"
        />
        <StatsCard
          title="Average Rating"
          value={parseFloat(stats.avgRating)}
          icon={Star}
          color="orange"
          trend={2}
          description="Based on student feedback"
        />
      </div>

      {/* Quick Actions */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        <div className="bg-gradient-to-br from-blue-50 to-blue-100 rounded-2xl p-6 border border-blue-200">
          <div className="flex items-center justify-between mb-4">
            <div className="p-3 bg-blue-500 rounded-xl">
              <BarChart3 className="w-6 h-6 text-white" />
            </div>
            <span className="text-blue-600 text-sm font-semibold">Analytics</span>
          </div>
          <h3 className="text-lg font-bold text-blue-900 mb-2">Course Performance</h3>
          <p className="text-blue-700 text-sm mb-4">View detailed analytics and insights</p>
          <button className="w-full bg-blue-500 text-white py-2 rounded-xl font-medium hover:bg-blue-600 transition-colors">
            View Analytics
          </button>
        </div>

        <div className="bg-gradient-to-br from-green-50 to-green-100 rounded-2xl p-6 border border-green-200">
          <div className="flex items-center justify-between mb-4">
            <div className="p-3 bg-green-500 rounded-xl">
              <Calendar className="w-6 h-6 text-white" />
            </div>
            <span className="text-green-600 text-sm font-semibold">Schedule</span>
          </div>
          <h3 className="text-lg font-bold text-green-900 mb-2">Upcoming Sessions</h3>
          <p className="text-green-700 text-sm mb-4">Manage your teaching schedule</p>
          <button className="w-full bg-green-500 text-white py-2 rounded-xl font-medium hover:bg-green-600 transition-colors">
            View Schedule
          </button>
        </div>

        <div className="bg-gradient-to-br from-purple-50 to-purple-100 rounded-2xl p-6 border border-purple-200">
          <div className="flex items-center justify-between mb-4">
            <div className="p-3 bg-purple-500 rounded-xl">
              <Award className="w-6 h-6 text-white" />
            </div>
            <span className="text-purple-600 text-sm font-semibold">Achievements</span>
          </div>
          <h3 className="text-lg font-bold text-purple-900 mb-2">Your Achievements</h3>
          <p className="text-purple-700 text-sm mb-4">Track your milestones</p>
          <button className="w-full bg-purple-500 text-white py-2 rounded-xl font-medium hover:bg-purple-600 transition-colors">
            View Badges
          </button>
        </div>
      </div>

      {/* Courses List */}
      <div style={{
        background: 'rgba(255,255,255,0.95)', 
        borderRadius: '25px', 
        boxShadow: '0 25px 50px rgba(0,0,0,0.1)', 
        border: '1px solid rgba(255,255,255,0.3)',
        backdropFilter: 'blur(20px)',
        overflow: 'hidden'
      }}>
        <div style={{padding: '2rem', borderBottom: '1px solid rgba(0,0,0,0.1)', background: 'linear-gradient(135deg, rgba(102,126,234,0.1) 0%, rgba(118,75,162,0.1) 100%)'}}>
          <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem'}}>
            <h2 style={{fontSize: '2rem', fontWeight: 'bold', color: '#1e293b', margin: 0}}>
              📚 My Courses ({filteredCourses.length})
            </h2>
          </div>
          <div style={{display: 'flex', gap: '1rem', alignItems: 'center'}}>
            <input
              type="text"
              placeholder="Search courses..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              style={{
                flex: 1,
                padding: '0.75rem 1rem',
                borderRadius: '25px',
                border: '2px solid rgba(102,126,234,0.2)',
                fontSize: '1rem',
                background: 'rgba(255,255,255,0.9)',
                outline: 'none'
              }}
            />
            <select
              value={filterLevel}
              onChange={(e) => setFilterLevel(e.target.value)}
              style={{
                padding: '0.75rem 1rem',
                borderRadius: '15px',
                border: '2px solid rgba(102,126,234,0.2)',
                fontSize: '1rem',
                background: 'rgba(255,255,255,0.9)',
                outline: 'none'
              }}
            >
              <option value="all">All Levels</option>
              <option value="Beginner">Beginner</option>
              <option value="Intermediate">Intermediate</option>
              <option value="Advanced">Advanced</option>
            </select>
          </div>
        </div>

        <div style={{padding: '2rem'}}>
          {filteredCourses.length === 0 ? (
            <div style={{textAlign: 'center', padding: '3rem', color: '#64748b'}}>
              <BookOpen style={{width: '4rem', height: '4rem', margin: '0 auto 1rem', opacity: 0.5}} />
              <h3 style={{fontSize: '1.5rem', fontWeight: '600', marginBottom: '0.5rem'}}>
                {searchTerm || filterLevel !== 'all' ? 'No Matching Courses' : 'No Courses Yet'}
              </h3>
              <p style={{fontSize: '1rem'}}>
                {searchTerm || filterLevel !== 'all' 
                  ? 'Try adjusting your search or filter criteria' 
                  : 'Click "Add Course" to create your first course'}
              </p>
            </div>
          ) : (
            <div style={{display: 'flex', flexDirection: 'column', gap: '1.5rem'}}>
              {filteredCourses.map(course => (
              <div key={course.id} style={{
                background: 'linear-gradient(135deg, rgba(255,255,255,0.9) 0%, rgba(255,255,255,0.7) 100%)', 
                padding: '2rem', 
                borderRadius: '20px', 
                border: '1px solid rgba(0,0,0,0.1)',
                boxShadow: '0 10px 30px rgba(0,0,0,0.1)',
                transition: 'all 0.3s ease',
                cursor: 'pointer'
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.transform = 'translateY(-5px)';
                e.currentTarget.style.boxShadow = '0 20px 40px rgba(0,0,0,0.15)';
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.transform = 'translateY(0)';
                e.currentTarget.style.boxShadow = '0 10px 30px rgba(0,0,0,0.1)';
              }}>
                <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center'}}>
                  <div style={{display: 'flex', alignItems: 'center', gap: '1.5rem'}}>
                    <img src={course.img} alt={course.title} style={{width: '5rem', height: '5rem', borderRadius: '15px', objectFit: 'cover', boxShadow: '0 8px 20px rgba(0,0,0,0.15)'}} />
                    <div>
                      <h3 style={{fontSize: '1.5rem', fontWeight: 'bold', color: '#1e293b', marginBottom: '0.5rem'}}>{course.title}</h3>
                      <p style={{color: '#64748b', marginBottom: '0.75rem', fontSize: '1rem'}}>{course.desc}</p>
                      <div style={{display: 'flex', alignItems: 'center', gap: '1.5rem', fontSize: '0.9rem'}}>
                        <span style={{color: '#16a34a', fontWeight: '700', fontSize: '1.1rem'}}>₹{course.price}</span>
                        <span style={{color: '#64748b', display: 'flex', alignItems: 'center', gap: '0.25rem'}}>
                          <Users style={{width: '1rem', height: '1rem'}} />
                          {course.enrolled} students
                        </span>
                        <span style={{color: '#d97706', display: 'flex', alignItems: 'center', gap: '0.25rem'}}>
                          <Star style={{width: '1rem', height: '1rem'}} />
                          {course.rating}
                        </span>
                        <span style={{
                          background: 'linear-gradient(45deg, #667eea, #764ba2)', 
                          color: 'white', 
                          padding: '0.25rem 0.75rem', 
                          borderRadius: '15px', 
                          fontSize: '0.8rem',
                          fontWeight: '600'
                        }}>
                          {course.level}
                        </span>
                      </div>
                    </div>
                  </div>
                  <div style={{display: 'flex', gap: '0.75rem'}}>
                    <button 
                      onClick={() => editCourse(course)}
                      style={{
                        padding: '0.75rem', 
                        background: 'linear-gradient(45deg, #667eea, #764ba2)', 
                        color: 'white', 
                        border: 'none', 
                        borderRadius: '12px', 
                        cursor: 'pointer',
                        boxShadow: '0 4px 15px rgba(102,126,234,0.3)',
                        transition: 'all 0.3s ease'
                      }}
                      title="Edit Course"
                    >
                      <Edit style={{width: '1.25rem', height: '1.25rem'}} />
                    </button>
                    <button 
                      onClick={() => previewCourse(course)}
                      style={{
                        padding: '0.75rem', 
                        background: 'linear-gradient(45deg, #11998e, #38ef7d)', 
                        color: 'white', 
                        border: 'none', 
                        borderRadius: '12px', 
                        cursor: 'pointer',
                        boxShadow: '0 4px 15px rgba(17,153,142,0.3)',
                        transition: 'all 0.3s ease'
                      }}
                      title="Preview Course"
                    >
                      <Eye style={{width: '1.25rem', height: '1.25rem'}} />
                    </button>
                    <button 
                      onClick={() => deleteCourse(course.id, course.title)}
                      style={{
                        padding: '0.75rem', 
                        background: 'linear-gradient(45deg, #ff6b6b, #ee5a24)', 
                        color: 'white', 
                        border: 'none', 
                        borderRadius: '12px', 
                        cursor: 'pointer',
                        boxShadow: '0 4px 15px rgba(255,107,107,0.3)',
                        transition: 'all 0.3s ease'
                      }}
                      title="Delete Course"
                    >
                      <Trash2 style={{width: '1.25rem', height: '1.25rem'}} />
                    </button>
                  </div>
                </div>
              </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Add Course Modal */}
      {showAddModal && (
        <div style={{position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, backgroundColor: 'rgba(0,0,0,0.6)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 50, backdropFilter: 'blur(5px)'}}>
          <div style={{
            background: 'linear-gradient(135deg, rgba(255,255,255,0.95) 0%, rgba(255,255,255,0.9) 100%)', 
            padding: '2.5rem', 
            borderRadius: '25px', 
            maxWidth: '40rem', 
            width: '100%', 
            margin: '0 1rem', 
            maxHeight: '90vh', 
            overflowY: 'auto',
            boxShadow: '0 25px 50px rgba(0,0,0,0.2)',
            border: '1px solid rgba(255,255,255,0.3)',
            backdropFilter: 'blur(20px)'
          }}>
            <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem'}}>
              <h2 style={{fontSize: '2rem', fontWeight: 'bold', color: '#1e293b', margin: 0}}>🎯 Add New Course</h2>
              <button 
                onClick={() => closeModal('add')}
                style={{
                  color: '#64748b', 
                  background: 'rgba(255,255,255,0.8)', 
                  border: 'none', 
                  padding: '0.5rem', 
                  cursor: 'pointer', 
                  borderRadius: '12px',
                  boxShadow: '0 4px 15px rgba(0,0,0,0.1)',
                  transition: 'all 0.3s ease'
                }}
                type="button"
              >
                <X style={{width: '1.5rem', height: '1.5rem'}} />
              </button>
            </div>

            <form onSubmit={handleAddSubmit} style={{display: 'flex', flexDirection: 'column', gap: '1.5rem'}}>
              <input 
                type="text" 
